// 获取输入数据
const data = $input.first().json;

// --- 1. 获取当前柏林时间 (原生 JS 写法) ---
// 容器内部通常是 UTC，我们用 Intl API 强制转换成柏林时间
const nowStr = new Date().toLocaleString("en-US", {timeZone: "Europe/Berlin"});
// 将转换后的时间字符串重新变成 Date 对象，用于比较
const now = new Date(nowStr);

// --- 2. 解析 API 数据 ---
// Open-Meteo 返回的已经是柏林时间的 ISO 字符串 (e.g. "2026-01-29T07:56")
// 我们直接 new Date()，虽然它会把这个时间当成容器本地时间(UTC)，
// 但因为上面的 'now' 也是同样逻辑生成的，所以两者的“相对时间”是对齐的，可以直接比较！
const sunrise = new Date(data.daily.sunrise[0]);
const sunset = new Date(data.daily.sunset[0]);
// 计算明天的日出 (简单加 24 小时)
const nextSunrise = new Date(sunrise.getTime() + 24 * 60 * 60 * 1000);

let status = "";
let timeDiffStr = "";

// --- 3. 核心逻辑 ---
if (now < sunrise) {
  status = "清晨";
  const diffMs = sunrise - now;
  const hours = Math.floor(diffMs / (1000 * 60 * 60));
  const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
  timeDiffStr = `${hours}小时${minutes}分钟后日出`;
} else if (now < sunset) {
  status = "白天";
  const diffMs = sunset - now;
  const hours = Math.floor(diffMs / (1000 * 60 * 60));
  const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
  timeDiffStr = `${hours}小时${minutes}分钟后日落`;
} else {
  status = "入夜";
  const diffMs = nextSunrise - now;
  const hours = Math.floor(diffMs / (1000 * 60 * 60));
  const minutes = Math.floor((diffMs % (1000 * 60 * 60)) / (1000 * 60));
  timeDiffStr = `${hours}小时${minutes}分钟后迎来日出`;
}

// 输出
return {
  json: {
    current_temp: data.current.temperature_2m,
    status: status,
    time_diff_str: timeDiffStr
  }
};
